    param([string]$Path)

    try {
        $zip = [System.IO.Compression.ZipFile]::OpenRead($Path)
        $entry = $zip.GetEntry("word/document.xml")
        if ($null -eq $entry) {
            $zip.Dispose()
            return "Error: word/document.xml not found in $Path"
        }

        $stream = $entry.Open()
        $reader = New-Object System.IO.StreamReader($stream, [System.Text.Encoding]::UTF8)
        $xmlText = $reader.ReadToEnd()
        $reader.Close()
        $stream.Close()
        $zip.Dispose()

        # Parse XML
        [xml]$xml = $xmlText
        $ns = New-Object System.Xml.XmlNamespaceManager $xml.NameTable
        $ns.AddNamespace("w", "http://schemas.openxmlformats.org/wordprocessingml/2006/main")

        # Select all paragraphs
        $paragraphs = $xml.SelectNodes("//w:p", $ns)
        $textList = New-Object System.Collections.Generic.List[string]

        foreach ($p in $paragraphs) {
            $runs = $p.SelectNodes(".//w:t", $ns)
            $pText = ""
            foreach ($r in $runs) {
                $pText += $r.InnerText
            }
            # We add empty lines to keep structure, or just non-empty
            $textList.Add($pText)
        }

        return $textList -join "`n"
    } catch {
        return "Error reading $Path: $_"
